def maxSlidingWindow(self, nums: list[int], k: int) -> list[int]:
    dq: deque[int] = deque()
    ans: list[int] = []
    for i, x in enumerate(nums):
        while dq and nums[dq[-1]] <= x:
            dq.pop()
        dq.append(i)
        if dq[0] <= i - k:
            dq.popleft()
        if i >= k - 1:
            ans.append(nums[dq[0]])
    return ans
